import React, { useState } from 'react';
import { Link } from 'react-router-dom';

const Nav = () => {
  const [searchQuery, setSearchQuery] = useState('');

  const handleSearch = (e) => {
    e.preventDefault();
    console.log('Searching for:', searchQuery);
  };

  return (
    <header className="header">
      <div className="header-top">
        <a href="/" className="logo">
          <div className="logo-icon">
            <i className="fas fa-carrot"></i>
          </div>
          Yeswanth's Healthy Kitchen
        </a>
        
        <div className="header-search">
          <div className="search-bar">
            <input 
              type="text" 
              id="searchInput" 
              placeholder="Search for the best food..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
            />
            <button className="search-btn" onClick={handleSearch}>
              <i className="fas fa-search"></i>
            </button>
          </div>
        </div>
        
        <div className="header-actions">
          <Link to="/login"><i className="fas fa-user"></i> Login</Link>
          <Link to="/signup"><i className="fas fa-user-plus"></i> Sign Up</Link>
          <a href="/cart" className="cart-link">
            <i className="fas fa-shopping-cart"></i>
            Cart
            <span className="cart-badge" style={{ display: 'none' }}>0</span>
          </a>
        </div>
      </div>
      
      <nav className="nav">
        <a href="/" className="active"><i className="fas fa-home"></i> Home</a>
        <a href="/menu"><i className="fas fa-utensils"></i> Menu</a>
        <a href="#"><i className="fas fa-percent"></i> Offers</a>
        <a href="#"><i className="fas fa-hamburger"></i> Food</a>
        <a href="#"><i className="fas fa-mug-hot"></i> Drinks</a>
        <a href="#"><i className="fas fa-blender"></i> Smoothies</a>
        <a href="#"><i className="fas fa-birthday-cake"></i> Desserts</a>
      </nav>
    </header>
  );
};

export default Nav;
